{
  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "Seedajt preezigi tam\nKUNGAam juhs Taif-\nnee/ teem Rahnieem\naatsti peenahkahs teikt.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Pateizeet tam KUNGAam\nKohklehm/ un dseedajt wiꞥ-\nan ar Sohma-Stabulehm/ un\ner Spehlehm no definitis Stih-\nahm.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Dseedajt wiꞥnam jaunu\nOseetnu/ spehlejeet labbi ar\nSkannu.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Jo ta KUNGA Wahrds\ner taifsne/ un wiꞥs wiꞥna Darbs\ner pectizzigs.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Wiꞥsch mihto Taifnibu\nn Teetu/ ta Semme irr pilna\no ta KUNGA Schehlastibas.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Zaur ta KUNGA Wahr-\nut irr tahs Debbeﬁs darritas/\nn wiꞥs/wiꞥnu Spehks zaur to\nBarru wiꞥna Muttes.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Wiꞥsch faakraij to Juha\nas Uhdeni ka Kohpu/ un leek\nohs Diłłumus Sleppenibá.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Bibsteetees no ta KUNGA\nwiﬀa Pasaule/ baiiojeetees\nreefftch winna wiﬀi Semmes\nEedshwotaji.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Kad wiꞥsch runna/ tad tas\noteek/ kad wiꞥsch paweht/ tad\nas tur stahw.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Las KUNGS istmižjina\njo Pagannu Padohmu/ wiꞥsch\ntalausch to Lauschu Dohmas.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "(Bet) ta KUNGA Pa-\ndohms pastahiw muhshigi/ wiꞥ-\nna Sirđs Dohmas lihds Rad-\ndu Raddeem.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Swehtiga irr ta Tanka/\nkam tas KUNGS par Deewu\nirr/ tee Landis/ ko wiꞥsch tewim\npar eemantojamu Teefu istweh-\nlejs.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Tas KUNGS skattabe\nno Debbeﬁm/ un usluhko wiꞥus\nSilweka Behrnus.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Wiꞥsch istuhkojahs no\nfawa stipra Krehsla us wiﬀeein/\nfas wirs Gemmes dsihwo.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Wiꞥsch notaifa wiﬀas\nwiꞥan Sirđis/ wiꞥch leek wiﬀ-\nfus wiꞥnu Darbus wehrá.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Weenam Rehnixam ne\ntobp zaun fawn leelu Spehtu\npalihdsehts/ weens Warrenajs\nne tobp isglahbts zaun fawn lee-\nlu Stiprumu.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Ir Sirgi ne warr palih-\ndseht/ un wiꞥnu leels Spehts\nne warr isglahbt.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Raugiy ta KUNGA Azź\nusluhko tohs/ kas wiꞥnu bih-\nstahs/ kas us wiꞥna Schehlasti-\nbu zerre.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Ka tas wiꞥnu Dwehfeli\nno Nahwes ispesti/ un Badda\nLaiká tohs dsihwus usturr.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Muhfu Dwebfele gaida\nus to KUNGU/ wiꞥsch irr\nmums par Patigu un preeftsch-\nturramahm Bruzzahm.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
